// Groq's classification is a JSON string inside choices[0].message.content.
// Parse it, and merge with the original email fields (which live on the
// Gmail Trigger output, two nodes back) so downstream nodes have everything.

const groqResponse = $input.first().json;
const rawContent = groqResponse.choices[0].message.content;

let classification;
try {
  classification = JSON.parse(rawContent);
} catch (e) {
  // Fallback if the model ever returns non-JSON — fail safe to manual review.
  classification = {
    intent: "other",
    priority: "normal",
    reason: "Could not parse classifier output: " + e.message,
    needs_reply: true
  };
}

// Pull the original email off the Gmail Trigger node by name.
const email = $('Gmail Trigger').first().json;

return [
  {
    json: {
      // classification
      intent: classification.intent,
      priority: classification.priority,
      reason: classification.reason,
      needs_reply: classification.needs_reply,
      // original email, normalised into flat fields
      emailId: email.id,
      threadId: email.threadId,
      subject: email.subject || "",
      fromName: email.from?.value?.[0]?.name || "",
      fromAddress: email.from?.value?.[0]?.address || "",
      bodyText: email.text || email.snippet || ""
    }
  }
];

