// Pull the AI-generated reply text from the Draft Reply (Groq) response.
const draftText = $input.first().json.choices[0].message.content.trim();

// Reach back to Parse Classification for the email metadata.
const meta = $('Parse Classification').first().json;

return [
  {
    json: {
      draftText: draftText,
      threadId: meta.threadId,
      emailId: meta.emailId,
      subject: meta.subject,
      toAddress: meta.fromAddress,   // we reply TO the original sender
      toName: meta.fromName,
      intent: meta.intent,
      priority: meta.priority,
      // pre-build the reply subject (Re: ...) once, reused downstream
      replySubject: meta.subject.startsWith("Re:") ? meta.subject : "Re: " + meta.subject
    }
  }
];

const resume = $input.first().json;
const decision =
  resume.query?.decision ||
  resume.decision ||
  (resume.body && resume.body.decision) ||
  "unknown";

const draft = $('Prepare Draft').first().json;

return [
  {
    json: {
      decision: decision,
      approved: decision === "approve",
      draftText: draft.draftText,
      threadId: draft.threadId,
      emailId: draft.emailId,
      toAddress: draft.toAddress,
      replySubject: draft.replySubject,
      intent: draft.intent,
      priority: draft.priority
    }
  }
];

const d = $('Parse Classification').first().json;
return [{
  json: {
    timestamp: new Date().toISOString(),
    action: "SKIPPED_SYSTEM_EMAIL",
    from: d.fromAddress,
    subject: d.subject
  }
}];

const d = $('Read Decision').first().json;
return [{
  json: {
    timestamp: new Date().toISOString(),
    action: "SENT",
    decision: d.decision,
    intent: d.intent,
    priority: d.priority,
    to: d.toAddress,
    subject: d.replySubject,
    threadId: d.threadId,
    draftPreview: (d.draftText || "").slice(0, 120)
  }
}];

const d = $('Read Decision').first().json;
return [{
  json: {
    timestamp: new Date().toISOString(),
    action: "REJECTED",
    decision: d.decision,
    intent: d.intent,
    priority: d.priority,
    to: d.toAddress,
    subject: d.replySubject,
    threadId: d.threadId,
    draftPreview: (d.draftText || "").slice(0, 120)
  }
}];
